import { getDataByKeys } from './../domain/data-by-keys';
import { getDistinct } from '../../utils/zcutils';
import { isExpressionType } from '../../mark/parser/parser-helpers';

/**
 * @param  {Array} array
 * @param  {[Array | Number | String]} keys
 * @return {Array}       [categories]
 */
export function getCategories(operators){
    let _scale = this,
    _parser = _scale.config,
    _chart = _scale.chartObj,
    data = operators.data, indices = operators.indices;

    if(!data){
        data = _chart.seriesdata.map((d, i) => {
            return d.data
        })
    }else if(isExpressionType(data)){
        let seriesIndices = data.seriesIndex;
        data = seriesIndices.map((d, i) => {
            return _chart.seriesdata[d].data;
        })
    }

    return categories(data, indices);

}
export function categories(array, keys) {
    var data = getDataByKeys(array, keys);
    return getDistinct(data);
}
